section.programlisting:
CharSequenceNormalizer chain = TextNormalizer.defaultChain();

// byte order mark stripped, curly quotes folded, case and accent folded
String t = chain.normalize("﻿“CafÉ”").toString();   // "\"cafe\""

OffsetAwareNormalizer pipeline = TextNormalizer.builder()
    .whitespace()      // collapses runs, so it changes length and shifts offsets
    .dashes()
    .buildAligned();

String original = "find   the—match";
AlignedText aligned = pipeline.normalizeAligned(original);
// aligned.normalized()                ->  "find the-match"
Span hit = aligned.toOriginalSpan(5, 14);   // "the-match" in the normalized text
// hit.getCoveredText(original)         ->  "the—match"   (back to the source, em dash and all)

InferenceOptions options = new InferenceOptions();
options.setNormalizeWhitespace(true);   // opt-in: NBSP, ideographic space, ... -> ASCII space
options.setNormalizeDashes(true);       // opt-in: en dash, em dash, ... -> hyphen-minus

NameFinderDL finder = new NameFinderDL(model, vocab, ids2Labels, options, sentenceDetector);

// fold only Latin, and do not map the stroke letters
CharSequenceNormalizer latinOnly = new AccentFoldCharSequenceNormalizer(
    java.util.Set.of(Character.UnicodeScript.LATIN), false);

TermAnalyzer analyzer = TermAnalyzer.builder()
    .caseFold()
    .stem(new PorterStemmer())
    .build();

Term term = analyzer.analyze("Running").get(0);
// term.original()           -> "Running"
// term.normalized()         -> "run"      (the final configured dimension, here STEM)
// term.peel()               -> "running"  (the layer below the top, O(1))
// term.at(Dimension.NFC)    -> computed lazily on first request, then cached

EmojiAnnotator annotator = new EmojiAnnotator();
TermAnalyzer analyzer = TermAnalyzer.builder().emojiFold().build();

// "Berlin <German flag> <red heart>"
String text = "Berlin \uD83C\uDDE9\uD83C\uDDEA \u2764\uFE0F";
for (Term term : analyzer.analyze(text)) {
  annotator.annotate(term).ifPresent(a -> {
    a.name();        // "red heart" for the heart (CLDR short name)
    a.sentiment();   // 2 for the heart (project-authored coarse score, -2..2)
    a.entityType();  // FLAG for the flag, HEART for the heart
    a.category();    // FLAGS / SMILEYS_AND_EMOTION
    a.isoRegion();   // "DE" for the flag, decoded from the sequence itself
  });
}

// "paypal" with Cyrillic a's looks identical but is a different code-point sequence
Confusables.confusable("paypal", spoofed);   // true
Confusables.skeleton("paypal");              // a matching key, not readable text

NormalizationProfile german = NormalizationProfiles.forLanguage("de").orElseThrow();
TermAnalyzer analyzer = german.matchingAnalyzer();   // NFC, case fold, German fold, German stemmer
// "Mueller" and "Müller" both reduce to the same matching term

// detect the language when it is not known
NormalizationProfiles.detect(text, languageDetector).map(NormalizationProfile::matchingAnalyzer);
